import { isUndefined } from 'lodash-es';

import { INCLUDE_ALL_WILDCARD_RULE } from '../constants.js';
import type { BaseLayerShapesRequestConfig } from '../types/base-layer-shapes-request-config.js';

const REGION_CODE_REGEX = /(?<code>.*)-.*/;

const hasIncludeAllWildCard = (include: string[]) =>
  include.includes(INCLUDE_ALL_WILDCARD_RULE);

const hasCountryCode = (include: string[]) =>
  include.find((value) => !value.includes('-'));

export const getBaseLayerShapesRequestConfig = (
  include: string[],
): BaseLayerShapesRequestConfig => {
  let includeWorldView = false;
  let countryRegions: string[] = [];

  if (hasIncludeAllWildCard(include) || hasCountryCode(include)) {
    includeWorldView = true;
  }

  const countryCodes = new Set<string>();
  for (let i = 0; i < include.length; i++) {
    const countryCode = REGION_CODE_REGEX.exec(include[i])?.groups?.code;
    if (!isUndefined(countryCode)) {
      countryCodes.add(countryCode);
    }
  }

  countryRegions = Array.from(countryCodes);

  return { includeWorldView, countryRegions };
};
